#include <stdio.h>

int main() {
    int n, k = 0;
    scanf("%d", &n);
    int denominations[] = {100, 20, 10, 5};
    for (int i = 0; i < 4; i++) {
        k += n / denominations[i];
        n %= denominations[i];
    }
    printf("%d\n", k + n);
    return 0;
}
